// Find the earliest Friday the 13th in the proleptic Gregorian calendar
// and count total Friday the 13ths in a full 400-year cycle.

// --- Earliest Friday the 13th starting from 0001-01-01 ---
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// --- Count Friday the 13ths in a full 400-year Gregorian cycle ---
int count = 0;
var start = new DateTime(1, 1, 13);
var end = new DateTime(401, 1, 1);

for (var d = start; d < end; d = d.AddMonths(1))
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        count++;
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle (0001–0400): {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// --- Bonus: distribution by day-of-week for the 13th ---
Console.WriteLine("\nDistribution of the 13th by day-of-week (400-year cycle):");
var tally = new int[7];
for (var d = start; d < end; d = d.AddMonths(1))
    tally[(int)d.DayOfWeek]++;

foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {dow,-10} {tally[(int)dow],4}");

